import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, CircleMarker, Tooltip } from "react-leaflet";
import { LineChart, Line, XAxis, YAxis, Tooltip as ReTooltip, CartesianGrid } from "recharts";
import 'leaflet/dist/leaflet.css';

const MapComponent = () => {
  const [buses, setBuses] = useState([]);
  const [showChart, setShowChart] = useState(false);

  // Fetch buses every 2 minutes
  useEffect(() => {
    const fetchBuses = async () => {
      try {
        const response = await fetch("http://localhost:8000/buses");
        const data = await response.json();
        console.log("Fetched buses:", data); // debug
        setBuses(data);
      } catch (err) {
        console.error("Error fetching bus data:", err);
      }
    };

    fetchBuses();
    const interval = setInterval(fetchBuses, 120000); // 2 minutes
    return () => clearInterval(interval);
  }, []);

  // Count bus statuses
  const normalCount = buses.filter(b => b.status === "normal").length;
  const ghostCount = buses.filter(b => b.status === "ghost").length;
  const anomalyCount = buses.filter(b => b.status === "anomaly").length;

  const trendData = [
    { time: new Date().toLocaleTimeString(), normal: normalCount, ghost: ghostCount, anomaly: anomalyCount }
  ];

  const getColor = (status) => {
    if (status === "ghost") return "red";
    if (status === "anomaly") return "orange";
    return "green";
  };

  return (
    <div style={{ width: "100vw", height: "100vh", position: "relative" }}>
      <MapContainer
        center={[40.7128, -74.0060]}
        zoom={11}
        style={{ width: "100%", height: "100%" }}
      >
        <TileLayer
          url="https://tiles.stadiamaps.com/tiles/alidade_smooth/{z}/{x}/{y}{r}.png"
          attribution='&copy; <a href="https://stadiamaps.com/">Stadia Maps</a>'
        />

        {buses.map((bus, idx) => (
          <CircleMarker
            key={bus.id || idx}
            center={[bus.lat, bus.lon]}
            radius={6}
            color={getColor(bus.status)}
            fillOpacity={0.8}
          >
            <Tooltip>
              <span>{bus.status.toUpperCase()}</span>
            </Tooltip>
          </CircleMarker>
        ))}
      </MapContainer>

      {/* Bottom Left Counters */}
      <div style={{
        position: "absolute",
        bottom: 10,
        left: 10,
        backgroundColor: "#fff",
        padding: 10,
        borderRadius: 8
      }}>
        <div>Normal: {normalCount}</div>
        <div>Ghost: {ghostCount}</div>
        <div>Anomaly: {anomalyCount}</div>
        <button onClick={() => setShowChart(!showChart)} style={{ marginTop: 5 }}>
          {showChart ? "Hide Chart" : "Show Chart"}
        </button>
      </div>

      {/* Trend Chart */}
      {showChart && (
        <div style={{
          position: "absolute",
          bottom: 80,
          left: 10,
          backgroundColor: "#fff",
          padding: 10,
          borderRadius: 8
        }}>
          <LineChart width={350} height={200} data={trendData}>
            <XAxis dataKey="time" />
            <YAxis />
            <ReTooltip />
            <CartesianGrid stroke="#f5f5f5" />
            <Line type="monotone" dataKey="normal" stroke="green" />
            <Line type="monotone" dataKey="ghost" stroke="red" />
            <Line type="monotone" dataKey="anomaly" stroke="orange" />
          </LineChart>
        </div>
      )}
    </div>
  );
};

export default MapComponent;
